sql:
SELECT achievement_name
FROM achievements
WHERE reward = '100 XP' AND player_id = 0;

SELECT game_name 
FROM games 
WHERE game_id IN (
    SELECT game_id 
    FROM game_updates
);

SELECT player_id, game_id, COUNT(*) AS num_achievements
FROM achievements
GROUP BY player_id, game_id;

SELECT game_name, rating AS average_rating
FROM games
WHERE rating > 4;

SELECT update_id, game_id, update_version, changelog
FROM game_updates
WHERE changelog LIKE '%patch%';

SELECT player_name 
FROM players 
WHERE rank = 'Diamond';

SELECT game_name, developer, genre, rating AS average_rating
FROM games
WHERE rating_count > 1000;

external_knowledge:
- 'seasoned adventurers' refers to players with a level greater than 10; 
- 'journeyed beyond the realm of novices' means players who have moved past the initial stages of the game;
- 'treasure trove of achievements' refers to the achievements obtained by the players;
- 'bustling network' implies a significant number of friends, specifically more than five.

